import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";
import { GoogleGenAI, Type } from "@google/genai";
import dotenv from "dotenv";

dotenv.config();

const app = express();
const PORT = 3000;

// Increase payload size limit to accept base64 image data
app.use(express.json({ limit: '20mb' }));
app.use(express.urlencoded({ limit: '20mb', extended: true }));

// Initialize GoogleGenAI client lazy/secure
const apiKey = process.env.GEMINI_API_KEY;
let ai: GoogleGenAI | null = null;

if (apiKey && apiKey !== "MY_GEMINI_API_KEY") {
  ai = new GoogleGenAI({
    apiKey: apiKey,
    httpOptions: {
      headers: {
        'User-Agent': 'aistudio-build',
      }
    }
  });
}

// API endpoint to process images using Gemini 3.5 Flash
app.post("/api/scan", async (req: express.Request, res: express.Response) => {
  try {
    const { image } = req.body;
    if (!image) {
       res.status(400).json({ error: "No image data provided" });
       return;
    }

    if (!ai) {
       res.status(500).json({ 
        error: "Gemini API client not initialized. Please ensure the GEMINI_API_KEY is configured in your Secrets panel." 
      });
      return;
    }

    // Clean base64 string
    const base64Data = image.replace(/^data:image\/\w+;base64,/, "");

    const promptText = `
      You are a specialized grading sheet optical reader. Analyze the provided image of a grading sheet section.
      The image contains three key components in sequence:
      1. A printed subject code (كود المادة) - typically an integer printed from 1 to 15.
      2. A QR Code or barcode containing the student's secret code (الرقم السري).
      3. A handwritten grade (الدرجة المكتوبة بخط اليد). The grade can be written in Eastern Arabic (Hindi) numerals (e.g., ٠, ١, ٢, ٣, ٤, ٥, ٦, ٧, ٨, ٩) or Western Arabic numerals (e.g., 0 to 100, potentially with decimals like 15.5 or half marks).

      Identify these values accurately:
      - printedSubjectCode: Look for the printed number representing the subject code (integer from 1 to 15).
      - qrCode: Read the QR Code content. If you can read it, return its exact alphanumeric content. If the QR code is clearly visible, extract its text.
      - handwrittenGrade: Read the handwritten score. Translate any Eastern Arabic/Hindi numerals (like ١٥) to Western standard numerals (like "15"). Return it as a string representing the grade (e.g., "17.5" or "20").

      Provide your confidence level for each field as well. If a field is not detected or is completely unreadable, return null for its value.
    `;

    const imagePart = {
      inlineData: {
        mimeType: "image/jpeg",
        data: base64Data,
      },
    };

    const textPart = {
      text: promptText,
    };

    // Helper to run generation for a specific model
    const runGenerationForModel = async (modelName: string) => {
      return await ai!.models.generateContent({
        model: modelName,
        contents: { parts: [imagePart, textPart] },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              printedSubjectCode: {
                type: Type.INTEGER,
                description: "The printed subject code detected (integer 1 to 15), or null if not detected."
              },
              qrCode: {
                type: Type.STRING,
                description: "The string text scanned from the QR code, or null if not detected."
              },
              handwrittenGrade: {
                type: Type.STRING,
                description: "The handwritten grade/score translated to a Western numeral string (e.g., '14.5' or '18'), or null if not detected."
              },
              subjectCodeConfidence: {
                type: Type.NUMBER,
                description: "Confidence from 0.0 to 1.0."
              },
              qrCodeConfidence: {
                type: Type.NUMBER,
                description: "Confidence from 0.0 to 1.0."
              },
              gradeConfidence: {
                type: Type.NUMBER,
                description: "Confidence from 0.0 to 1.0."
              }
            },
            required: ["printedSubjectCode", "qrCode", "handwrittenGrade"]
          }
        }
      });
    };

    const retryWithBackoff = async <T>(fn: () => Promise<T>, modelName: string, retries = 2, delay = 1000): Promise<T> => {
      try {
        return await fn();
      } catch (err: any) {
        const errorMsg = err?.message || "";
        const isTransient = err?.status === 503 || err?.code === 503 || err?.statusCode === 503 ||
                            err?.status === 429 || err?.code === 429 || err?.statusCode === 429 ||
                            errorMsg.includes("503") ||
                            errorMsg.toLowerCase().includes("high demand") ||
                            errorMsg.toLowerCase().includes("unavailable") ||
                            errorMsg.toLowerCase().includes("temporary") ||
                            errorMsg.toLowerCase().includes("resource exhausted") ||
                            errorMsg.toLowerCase().includes("rate limit") ||
                            errorMsg.toLowerCase().includes("quota");
        
        if (retries > 0 && isTransient) {
          console.warn(`[Gemini API] Model ${modelName} is busy/exhausted (503/429). Retrying in ${delay}ms... (${retries} attempts remaining)`);
          await new Promise(resolve => setTimeout(resolve, delay));
          return retryWithBackoff(fn, modelName, retries - 1, delay * 1.5);
        }
        throw err;
      }
    };

    const modelsToTry = [
      "gemini-3.5-flash",
      "gemini-flash-latest",
      "gemini-3.1-flash-lite"
    ];

    let lastError: any = null;
    let response: any = null;

    for (const model of modelsToTry) {
      try {
        console.log(`[Gemini API] Attempting scan using model: ${model}`);
        response = await retryWithBackoff(() => runGenerationForModel(model), model, 2, 1200);
        console.log(`[Gemini API] Scan successful using model: ${model}`);
        break; // Success! Exit the loop
      } catch (err: any) {
        lastError = err;
        console.warn(`[Gemini API] Model ${model} failed: ${err.message || err}. Trying next model...`);
      }
    }

    if (!response) {
      throw lastError || new Error("All candidate models failed to process the scanning request.");
    }

    const resultText = response.text;
    if (!resultText) {
      throw new Error("Empty response from Gemini API");
    }

    const parsedResult = JSON.parse(resultText);
     res.json({ success: true, result: parsedResult });
  } catch (error: any) {
    console.error("Scanning Error:", error);
     res.status(500).json({ success: false, error: error.message || "An error occurred during scanning" });
  }
});

// Configure Vite or Static File Serving
async function startServer() {
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

startServer();
